(async () => {
  // Spell Cost by Rank
  const SPELLBOOK_COST_BY_RANK = {
    0: 2, // cantrips
    1: 2,
    2: 6,
    3: 16,
    4: 36,
    5: 70,
    6: 140,
    7: 300,
    8: 650,
    9: 1500,
    10: 7000,
  };

  // 1. Ensure exactly one token is selected
  if (canvas.tokens.controlled.length !== 1) {
    ui.notifications.error("You must select exactly one token first.");
    return;
  }

  const actor = canvas.tokens.controlled[0].actor;

  if (!actor) {
    ui.notifications.error("Selected token has no actor.");
    return;
  }

  // 2. Find Spellbook Item
  let spellbook = actor.items.find((i) =>
    i.name.toLowerCase().startsWith("spellbook")
  );

  // 3. Create Spellbook if missing
  if (!spellbook) {
    const created = await actor.createEmbeddedDocuments("Item", [
      {
        name: "Spellbook",
        type: "equipment",
        img: "icons/sundries/books/book-symbol-spiral-silver-blue.webp",
        system: {
          price: { value: { gp: 0 } },
          description: { value: "<p><strong>Spellbook</strong></p>" },
        },
      },
    ]);

    spellbook = created[0];
  }

  // 4. Create entries for Dialog
  const entries = actor.spellcasting.collections.contents;

  // 5. Dialog content
  const dialogContent = `
  <form>
    <p>Select spellcasting entries to include:</p>
    ${entries.map((entry, index) => {
      const category = entry.entry.system?.prepared?.value ?? "unknown";

      return `
        <div class="form-group">
          <label>
            <input type="checkbox" name="entry" value="${index}"
              ${category === "prepared" || category === "spontaneous" ? "checked" : ""}>
            <strong>${entry.name}</strong>
            <em>(${category})</em>
          </label>
        </div>
      `;
    }).join("")}
  </form>
  `;

  // 6. Calculation Dialog
  new Dialog({
    title: "Spellbook Cost Calculation",
    content: dialogContent,
    buttons: {
      calculate: {
        label: "Calculate",
        callback: async (html) => {

          let totalCost = 0;

          // Track spell details for description
          const spellbookEntries = [];

          const selectedIndexes = html
            .find('input[name="entry"]:checked')
            .map((_, el) => Number(el.value))
            .get();

          for (const index of selectedIndexes) {

            const entry = entries[index];

            const spellLines = [];

            for (const spell of entry.contents) {

              const rank = spell.system.level?.value ?? 0;
              const cost = SPELLBOOK_COST_BY_RANK[rank] ?? 0;

              totalCost += cost;

              spellLines.push({
                name: spell.name,
                rank,
                cost
              });
            }

            // Sort spells by rank then name
            spellLines.sort((a, b) => {
              if (a.rank !== b.rank) return a.rank - b.rank;
              return a.name.localeCompare(b.name);
            });

            spellbookEntries.push({
              entryName: entry.name,
              spells: spellLines
            });
          }

          // Build description HTML
          let descriptionHTML = `
            <p><strong>Spellbook</strong></p>
            <p>Total Value: <strong>${totalCost} gp</strong></p>
            <hr/>
          `;

          for (const entryData of spellbookEntries) {

            descriptionHTML += `
              <h2>${entryData.entryName}</h2>
              <ul>
            `;

            for (const spellData of entryData.spells) {

              const rankLabel =
                spellData.rank === 0
                  ? "Cantrip"
                  : `Rank ${spellData.rank}`;

              descriptionHTML += `
                <li>
                  <strong>${spellData.name}</strong>
                  (${rankLabel}) — ${spellData.cost} gp
                </li>
              `;
            }

            descriptionHTML += `</ul>`;
          }

          // Update spellbook
          await spellbook.update({
            "system.price.value.gp": totalCost,
            "system.description.value": descriptionHTML,
          });

          ChatMessage.create({
            content: `
              <strong>Spellbook updated:</strong><br>
              ${actor.name}<br>
              Value: ${totalCost} gp
            `,
            whisper: [],
          });
        },
      },

      cancel: {
        label: "Cancel",
      },
    },

    default: "calculate",
  }).render(true);

})();
